runDeltaRatingTestCase(t, deltaRatingTestCase{
    price: *productcatalog.NewPriceFrom(productcatalog.UnitPrice{Amount: alpacadecimal.NewFromInt(10)}),
    phases: []deltaRatingPhase{
        {
            period:          periods.period1,
            meteredQuantity: 5,
            expectedDetailedLines: []ratingtestutils.ExpectedDetailedLine{
                {
                    ChildUniqueReferenceID: billingrating.UnitPriceUsageChildUniqueReferenceID,
                    Category:              stddetailedline.CategoryRegular,
                    ServicePeriod:         lo.ToPtr(periods.period1),
                    PerUnitAmount:         10, Quantity: 5,
                    Totals: ratingtestutils.ExpectedTotals{Amount: 50, Total: 50},
                },
            },
            expectedTotals: ratingtestutils.ExpectedTotals{Amount: 50, Total: 50},
        },
    },
})

type myGenerator struct{}
func (myGenerator) CurrentOnly(line usagebased.DetailedLine) (string, error) {
    return line.ChildUniqueReferenceID, nil
}
func (myGenerator) MatchedDelta(current, _ usagebased.DetailedLine) (string, error) {
    return current.ChildUniqueReferenceID, nil
}
func (myGenerator) PreviousOnlyReversal(line usagebased.DetailedLine) (string, error) {
    if line.ID == "" { return "", fmt.Errorf("line id required for correction") }
    return fmt.Sprintf("%s#correction:detailed_line_id=%s", line.PricerReferenceID, line.ID), nil
}
